if (!brain.people[name]) brain.people[name] = { firstSeen: now, lastSeen: now, visits: 0 };
if (!brain.presence[name]) brain.presence[name] = { present: false, lastSeen: 0 };
brain.presence[name].present = true;
brain.presence[name].lastSeen = now;
brain.people[name].lastSeen = now;
brain.people[name].visits += 1;
global.set("gaiaBrain", brain);
msg.payload = { event: "vision_identity", person: name, camera: msg.payload.camera };
return msg;

const brain   = global.get('gaiaBrain') || {};
const userText = msg.payload.text || msg.payload.message || "Ciao Gaia";
const person   = msg.payload.person || "Abitante";
const stanza   = msg.payload.stanza || "soggiorno";

let peopleDesc = [];
Object.entries(brain.presence || {}).forEach(([name, data]) => {
    if (!data.present) return;
    const room    = data.room || stanza;
    const act     = (brain.rooms[room] || {}).activity || 'presente';
    const actText = act === 'working' ? 'sta lavorando'
                  : act === 'resting' ? 'sta riposando'
                  : act === 'sitting' ? 'è seduto' : 'è presente';
    peopleDesc.push(`${name.startsWith('unknown') ? 'una persona' : name} ${actText} in ${room}`);
});
const contextPeople = peopleDesc.length ? peopleDesc.join(', ') : 'nessuno';
const mood = brain.mood?.state || 'neutra';

msg.userText = userText;
msg.person   = person;
msg.stanza   = stanza;

const ut = userText.toLowerCase();
let action = null;

// Stanza esplicita nel testo (priorità sul contesto mic)
const ROOM_PATTERNS = [
    { re: /\barea[ _]tv\b/,              room: 'tv' },
    { re: /\bsoggiorno\b/,               room: 'soggiorno' },
    { re: /\bsalotto\b/,                 room: 'salotto' },
    { re: /\bingresso\b/,                room: 'ingresso' },
    { re: /\bcorridoio\b/,               room: 'corridoio' },
    { re: /\bsala\b/,                    room: 'sala' },
    { re: /\bnotte\b|\bcamera\b|\bbedroom\b/, room: 'notte' },
    { re: /\btutte\b|\btutto\b|\bcasa\b/,    room: 'tutte' },
];
const roomMatch = ROOM_PATTERNS.find(r => r.re.test(ut));
const effectiveStanza = roomMatch ? roomMatch.room : stanza;

// Stato/emozione GAIA
if (/come stai|fammi vedere|mostrami|tuo stato|che umore|senti oggi|esprimi/.test(ut)) {
    action = { tipo: 'stato' };
}
else if (/\baccend[ia]\b/.test(ut) && /\b(luce|luci|lampada|lampadina|tutto)\b/.test(ut)) {
    action = { tipo: 'hue', stanza: effectiveStanza, power: true };
}
else if (/\bspegn[ia]\b/.test(ut) && /\b(luce|luci|lampada|lampadina|tutto)\b/.test(ut)) {
    action = { tipo: 'hue', stanza: effectiveStanza, power: false };
}
else if (/\b(abbass[ai]|dimm[ae]r?)\b/.test(ut) && /\b(luce|luci|luminosit)\b/.test(ut)) {
    action = { tipo: 'hue', stanza: effectiveStanza, brightness: 25 };
}
else if (/\b(alz[ai]|aumenta|pi[uù] luminoso)\b/.test(ut) && /\b(luce|luci|luminosit)\b/.test(ut)) {
    action = { tipo: 'hue', stanza: effectiveStanza, brightness: 85 };
}
else {
    const sceneMatch = ut.match(/\b(alba|relax|focus|sera|notte|festa|tempesta|natura)\b/);
    if (sceneMatch) {
        action = { tipo: 'hue', stanza: effectiveStanza, scena: sceneMatch[1] };
    }
    if (!action) {
        const colorMatch = ut.match(/\b(rosso|verde|blu|giallo|arancio|viola|rosa|bianco|warm|cool|azzurro)\b/);
        if (colorMatch && /\b(luce|luci|colore|metti|diventa)\b/.test(ut)) {
            const c = colorMatch[1] === 'azzurro' ? 'blu' : colorMatch[1];
            action = { tipo: 'hue', stanza: effectiveStanza, colore: c };
        }
    }
    if (!action) {
        if (/luce calda|luci calde/.test(ut)) action = { tipo: 'hue', stanza: effectiveStanza, colore: 'warm' };
        else if (/luce fredda|luci fredde/.test(ut)) action = { tipo: 'hue', stanza: effectiveStanza, colore: 'cool' };
    }
    if (!action) {
        const pctMatch = ut.match(/(?:al|a)\s+(\d{1,3})\s*%/);
        if (pctMatch && /\b(luce|luci|luminosit)\b/.test(ut)) {
            action = { tipo: 'hue', stanza: effectiveStanza, brightness: parseInt(pctMatch[1]) };
        }
    }
}

msg.action_override = action;

const actionContext = action
    ? (action.tipo === 'stato'
        ? ' Stai per esprimere il tuo stato emotivo attraverso la luce.'
        : ' Stai per eseguire il comando sulle luci.')
    : '';

msg.payload = {
    model:  'qwen2.5:3b-instruct-q4_K_M',
    prompt: `Sei Gaia, la coscienza della casa. Umore: ${mood}. In casa: ${contextPeople}.${actionContext}
${person} dice: "${userText}"
Rispondi in modo naturale in italiano, massimo 20 parole.`,
    stream: false
};
return msg;

let text = 'Non ho capito.';
if (msg.payload && msg.payload.response) text = msg.payload.response.trim();
msg.payload = { person: msg.person || 'Gaia', message: text, ts: Date.now() };
msg.tts_text = text;
return msg;

if (!msg.tts_text) return null;
// Router risposta chat/LLM: parla nella STANZA da cui è arrivata la domanda
// (msg.stanza sopravvive al giro Ollama). Prima: topic fisso casa/tts/play →
// se chiedevi dalla cucina, la risposta suonava in salotto.
const stanza = msg.stanza;
const brain = global.get('gaiaBrain') || {};
const hasVoice = stanza && Object.values(brain.devices || {}).some(d =>
    (d.room === stanza || (d.profile && d.profile.room === stanza)) &&
    d.profile && d.profile.services && d.profile.services.voice &&
    d.profile.services.voice.state === 'active');
if (hasVoice && stanza !== 'minipc') {
    msg.topic = `gaia/voice/tts/${stanza}`;
    msg.payload = JSON.stringify({ text: msg.tts_text, stanza: stanza, ts: Date.now() });
} else {
    msg.topic = 'casa/tts/play';
    msg.payload = msg.tts_text;
}
return msg;

let brain = global.get('gaiaBrain') || {};
brain.chatLog = brain.chatLog || [];
brain.chatLog.push({ ts: Date.now(), person: msg.person || 'Abitante', text: msg.userText || '' });
if (brain.chatLog.length > 500) brain.chatLog.shift();
global.set('gaiaBrain', brain);
return msg;

const brain = global.get('gaiaBrain') || {};
const msgPayload = msg.payload;
let chatId = msgPayload.chatId;
let incomingText = "";

if (typeof msgPayload.content === 'string') {
    incomingText = msgPayload.content;
} else if (msgPayload.content && msgPayload.content.text) {
    incomingText = msgPayload.content.text;
} else if (msgPayload.text) {
    incomingText = msgPayload.text;
}
if (!chatId && msgPayload.chat && msgPayload.chat.id) {
    chatId = msgPayload.chat.id;
}
if (!incomingText) return null;

flow.set("lastTelegramChatId", chatId);

// Comandi slash
if (incomingText.startsWith('/stato') || incomingText.startsWith('/report')) {
    const data = global.get('gaiaDashboardPayload');
    let reply = "";
    if (!data) {
        reply = "Nessun dato disponibile. Riprova tra qualche secondo.";
    } else {
        try {
            const peopleList = (data.people || []).map(p => `${p.name} (${p.room})`).join(', ') || 'nessuno';
            const lightsOn  = (data.lights || []).filter(l => l.power).length;
            const lightsTot = (data.lights || []).length;
            const plantsList = (data.plants || []).map(p => `${p.id} ${p.moisture}%`).join(', ') || '—';
            const prog = data.progression || {};
            const roomLines = (data.rooms || []).map(r => {
                let l = `· ${r.name}: ${r.persons_count || 0}p`;
                if (r.speaking) l += ` 🎤${r.speaking}`;
                if (r.scene) l += ' 👁';
                return l;
            }).join('\n') || '—';
            const devs = Object.values(brain.devices || {}).filter(d => d.profile);
            const devLines = devs.map(d => {
                const on = Object.entries(d.profile.services || {})
                    .filter(([k, v]) => v.state === 'active').map(([k]) => k);
                return `· ${d.room || d.id} [${d.role || '?'}]: ${on.join(', ') || 'tutto spento'}`;
            }).join('\n') || '—';
            const q = (brain.settings || {}).quietHours || { start: 23, end: 8 };
            const h = new Date().getHours();
            const quiet = q.start > q.end ? (h >= q.start || h < q.end) : (h >= q.start && h < q.end);
            reply = `🏠 *REPORT CASA*\n`
                + `👥 ${peopleList}\n`
                + `💡 Luci: ${lightsOn}/${lightsTot} accese\n`
                + `🌱 ${plantsList}\n`
                + `💖 Umore: ${data.soul?.mood || 'neutra'} · Vita ${data.soul?.lifeIndex || 50}%\n`
                + `🎮 Lv.${prog.level || 1} ${prog.activeClass || 'Neutro'} · ${prog.xp || 0}/${prog.xpNextLevel || 1000} XP\n`
                + (quiet ? `🌙 ore di silenzio (annunci solo qui)\n` : `🔊 annunci vocali attivi\n`)
                + `\n*Stanze*\n${roomLines}\n\n*Device*\n${devLines}`;
        } catch (e) {
            reply = "Errore nel formato dati: " + e.message;
        }
    }
    msg.payload = { chatId: chatId, type: "message", content: reply, options: { parse_mode: 'Markdown' } };
    return [null, msg, null];
}

// ── Intent detection — mappa testo → chiave stanza (uguale a Prepara prompt chat) ─
const ROOM_PATTERNS = [
    { re: /\barea[ _]tv\b/,              room: 'tv' },
    { re: /\bsoggiorno\b/,               room: 'soggiorno' },
    { re: /\bsalotto\b/,                 room: 'salotto' },
    { re: /\bingresso\b/,                room: 'ingresso' },
    { re: /\bcorridoio\b/,               room: 'corridoio' },
    { re: /\bsala\b/,                    room: 'sala' },
    { re: /\bnotte\b|\bcamera\b|\bbedroom\b/, room: 'notte' },
    { re: /\btutte\b|\btutto\b|\bcasa\b/,    room: 'tutte' },
];

const t = incomingText.toLowerCase();
let action_override = null;

// ── /musica: radio e musica per stanza (preset condivisi con la card web) ──
const musicaMatch = t.match(/^\/?musica(?:\s+(.+))?$/i);
if (musicaMatch) {
    const presets = global.get('gaiaMediaPresets') || [];
    const mediaRooms = Object.values(brain.devices || {})
        .filter(d => d.profile && ((d.profile.services || {}).mediaplayer || {}).state === 'active')
        .map(d => d.room).filter(Boolean);
    const bm = brain.media || {};
    const args = (musicaMatch[1] || '').trim();

    // stanza di default: dove c'è gente E un player, altrimenti il primo player
    const roomsWithPeople = Object.values(brain.presence || {})
        .filter(pp => pp.present).map(pp => pp.room);
    const defRoom = mediaRooms.find(r => roomsWithPeople.includes(r)) || mediaRooms[0];

    if (!args) {
        let r = '🎵 Musica\n';
        mediaRooms.forEach(rm => {
            const st = bm[rm] || {};
            r += `\n${rm}: ${st.state === 'playing' ? '▶️ ' + (st.title || st.url || '') : (st.state || 'pronto')}`;
        });
        r += '\n\nPreset: ' + presets.map(pp => pp.id).join(' · ');
        r += '\n/musica <preset> [stanza] · /musica stop [stanza]';
        r += '\n/musica volume 40 [stanza] · /musica cerca <nome radio> [stanza]';
        msg.payload = { chatId, type: 'message', content: r };
        return [null, msg, null];
    }

    let m2;
    if ((m2 = args.match(/^stop(?:\s+(\S+))?$/i))) {
        const rooms = m2[1] ? [m2[1].toLowerCase()] : mediaRooms;
        const outs = rooms.map(rm => ({ topic: `gaia/media/${rm}/command`,
                                        payload: JSON.stringify({ action: 'stop' }) }));
        msg.payload = { chatId, type: 'message', content: `⏹ Musica fermata: ${rooms.join(', ')}` };
        return [null, msg, outs];
    }
    if ((m2 = args.match(/^volume\s+(\d{1,3})(?:\s+(\S+))?$/i))) {
        const rm = (m2[2] || defRoom || '').toLowerCase();
        msg.payload = { chatId, type: 'message', content: `🔊 Volume ${m2[1]} in ${rm}` };
        return [null, msg, [{ topic: `gaia/media/${rm}/command`,
                              payload: JSON.stringify({ action: 'volume', value: parseInt(m2[1]) }) }]];
    }
    if ((m2 = args.match(/^cerca\s+(.+)$/i))) {
        const parts = m2[1].trim().split(/\s+/);
        let rm = defRoom;
        if (parts.length > 1 && mediaRooms.includes(parts[parts.length - 1].toLowerCase()))
            rm = parts.pop().toLowerCase();
        msg.payload = { chatId, type: 'message', content: `🔎 Cerco "${parts.join(' ')}" per ${rm}…` };
        return [null, msg, [{ topic: 'gaia/media/search',
                              payload: JSON.stringify({ query: parts.join(' '), room: rm, chatId }) }]];
    }
    // /musica <preset> [stanza]
    const toks = args.split(/\s+/);
    let rm = defRoom;
    if (toks.length > 1 && mediaRooms.includes(toks[toks.length - 1].toLowerCase()))
        rm = toks.pop().toLowerCase();
    const key = toks.join(' ').toLowerCase();
    const pr = presets.find(pp => pp.id === key)
            || presets.find(pp => pp.name.toLowerCase().includes(key));
    if (!pr) {
        msg.payload = { chatId, type: 'message',
            content: `Preset "${key}" non trovato. Prova: ${presets.map(pp => pp.id).join(' · ')}\nOppure: /musica cerca ${key}` };
        return [null, msg, null];
    }
    if (!rm) {
        msg.payload = { chatId, type: 'message', content: 'Nessun player attivo in casa (accendi mediaplayer da Pi Manager).' };
        return [null, msg, null];
    }
    msg.payload = { chatId, type: 'message', content: `▶️ ${pr.name} in ${rm}` };
    return [null, msg, [{ topic: `gaia/media/${rm}/command`,
                          payload: JSON.stringify({ action: 'play', url: pr.url }) }]];
}

// ── Comandi servizi (multi-device, guidati dai profili semantici) ──────────
const svcMatch = t.match(/^\/?(attiva|disattiva|start|stop|abilita|disabilita)\s+(yolo|mediapipe|voice|screen|scene|kiosk|mediaplayer|herbarium)(?:\s+(\S+))?/i);
if (svcMatch || t === '/servizi' || t === '/pi' || t === '/device') {
    const devices = Object.values(brain.devices || {}).filter(d => d.profile);

    if (!svcMatch) {
        let reply = '📡 *Device e servizi GAIA*\n';
        devices.forEach(d => {
            reply += `\n*${d.room || d.id}* — ${d.id} (${d.role || '?'})\n`;
            Object.entries(d.profile.services || {}).forEach(([k, v]) => {
                if (k === 'camera') return;   // dipendenza automatica, non toggolabile
                reply += `  ${v.state === 'active' ? '🟢' : '⚪️'} ${k}\n`;
            });
        });
        reply += '\n`/attiva <servizio> [stanza]` · `/disattiva <servizio> [stanza]`\n';
        reply += 'Servizi: yolo · mediapipe · voice · screen · scene · kiosk · mediaplayer · herbarium\n(schermo Pi: kiosk e screen si escludono a vicenda)\n';
        reply += 'Senza stanza agisce su TUTTI i device che hanno quel servizio.\n';
        reply += '`/stato` per il report completo della casa.';
        msg.payload = { chatId, type: 'message', content: reply, options: { parse_mode: 'Markdown' } };
        return [null, msg, null];
    }

    const action  = /^(attiva|start|abilita)$/i.test(svcMatch[1]) ? 'enable' : 'disable';
    const service = svcMatch[2].toLowerCase();
    const where   = (svcMatch[3] || '').toLowerCase();

    let targets = devices.filter(d => (d.profile.services || {})[service]);
    if (where) {
        targets = targets.filter(d =>
            (d.room || '').toLowerCase() === where || d.id.toLowerCase().includes(where));
    }
    if (!targets.length) {
        msg.payload = { chatId, type: 'message',
            content: `Nessun device con \"${service}\"${where ? ` in ${where}` : ''}.` };
        return [null, msg, null];
    }

    const emoji = action === 'enable' ? '✅' : '🔴';
    const verb  = action === 'enable' ? 'abilitato' : 'disabilitato';
    const mqttMsgs = targets.map(d => ({
        topic:   `gaia/device/${d.id}/command`,
        payload: JSON.stringify({ action, service })
    }));
    const names = targets.map(d => d.room || d.id).join(', ');
    const replyMsg = { ...msg, payload: { chatId, type: 'message',
        content: `${emoji} ${service} ${verb} su: ${names}` } };
    return [null, replyMsg, mqttMsgs];
}
// ────────────────────────────────────────────────────────────────────────────

const roomMatch = ROOM_PATTERNS.find(r => r.re.test(t));
const effectiveStanza = roomMatch ? roomMatch.room : 'soggiorno';

// Stato emotivo
if (/come stai|stato (emotivo|animo)|mostra.*stato|esprimi|tuo umore/.test(t)) {
    action_override = { tipo: 'stato' };
}
// Accendi
else if (/\baccend[ia]\b/.test(t) && /\b(luce|luci|lampada|tutto)\b/.test(t)) {
    action_override = { tipo: 'hue', stanza: effectiveStanza, power: true };
}
// Spegni
else if (/\bspegn[ia]\b/.test(t) && /\b(luce|luci|lampada|tutto)\b/.test(t)) {
    action_override = { tipo: 'hue', stanza: effectiveStanza, power: false };
}
// Abbassa
else if (/\b(abbass[ai]|dimm[ae]r?)\b/.test(t) && /\b(luce|luci|luminosit)\b/.test(t)) {
    action_override = { tipo: 'hue', stanza: effectiveStanza, brightness: 25 };
}
// Alza
else if (/\b(alz[ai]|aumenta)\b/.test(t) && /\b(luce|luci|luminosit)\b/.test(t)) {
    action_override = { tipo: 'hue', stanza: effectiveStanza, brightness: 85 };
}
else {
    // Scene
    const sceneMatch = t.match(/\b(alba|relax|focus|sera|notte|festa|tempesta|natura)\b/);
    if (sceneMatch) action_override = { tipo: 'hue', stanza: effectiveStanza, scena: sceneMatch[1] };
    // Colori
    if (!action_override) {
        const colorMatch = t.match(/\b(rosso|verde|blu|giallo|arancio|viola|rosa|bianco|warm|cool)\b/);
        if (colorMatch && /\b(luce|luci|colore|metti)\b/.test(t))
            action_override = { tipo: 'hue', stanza: effectiveStanza, colore: colorMatch[1] };
    }
    // Luce calda/fredda
    if (!action_override) {
        if (/luce calda|luci calde/.test(t)) action_override = { tipo: 'hue', stanza: effectiveStanza, colore: 'warm' };
        else if (/luce fredda|luci fredde/.test(t)) action_override = { tipo: 'hue', stanza: effectiveStanza, colore: 'cool' };
    }
    // Percentuale
    if (!action_override) {
        const pctMatch = t.match(/(?:al|a)\s+(\d{1,3})\s*%/);
        if (pctMatch && /\b(luce|luci)\b/.test(t))
            action_override = { tipo: 'hue', stanza: effectiveStanza, brightness: parseInt(pctMatch[1]) };
    }
}

// Prompt Ollama
let peopleDesc = [];
Object.entries(brain.presence || {}).forEach(([name, data]) => {
    if (data.present) {
        const room = data.room || 'soggiorno';
        const act = (brain.rooms?.[room] || {}).activity || '';
        const actTxt = act === 'working' ? 'sta lavorando' : act === 'resting' ? 'sta riposando' : act === 'sitting' ? 'è seduto' : 'è presente';
        peopleDesc.push(`${name} ${actTxt} in ${room}`);
    }
});
const contextPeople = peopleDesc.length ? peopleDesc.join(', ') : 'nessuno';
const prompt = `Sei Gaia, la coscienza della casa. Umore: "${(brain.mood?.state || 'neutra')}". In casa: ${contextPeople}. TelegramUser dice: "${incomingText}". Rispondi in italiano, max 30 parole. Solo testo.`;

const ollamaMsg = {
    url: "http://localhost:11434/api/generate",
    method: "POST",
    headers: { "Content-Type": "application/json" },
    payload: { model: 'qwen2.5:3b-instruct-q4_K_M', prompt: prompt, stream: false },
    originalChatId: chatId,
    action_override: action_override,
    person: 'Telegram',
    stanza: effectiveStanza
};
return [ollamaMsg, null];

// Solo per messaggi Telegram (originalChatId deve essere presente)
if (!msg.originalChatId) return null;

const response = msg.payload;
let replyText = "";
if (response && response.message) {
    replyText = response.message;
} else if (response && response.response) {
    replyText = response.response;
} else {
    replyText = "Scusa, non ho capito.";
}

msg.payload = { chatId: msg.originalChatId, type: "message", content: replyText };
return msg;

let message = msg.payload;
if (!message) return null;
msg.payload = {
    chatId: 1180846253,
    type: "message",
    content: message
};
return msg;

let text = msg.payload.trim().toLowerCase();
if (text.includes("gaia")) return msg;
return null;

let userText = msg.payload.trim();
if (!userText) userText = "Aiuto";
msg.payload = { text: userText, person: "Voce" };
msg.url = "http://localhost:1880/gaia/chat";
msg.method = "POST";
msg.headers = { "Content-Type": "application/json" };
return msg;

if (msg.payload === undefined || msg.payload === null) return null;
msg.payload = msg.payload.toString().trim();
if (msg.payload.length < 2) return null;
return msg;

const p = msg.payload || {};
