// ─────────────────────────────────────────────────────────────────────────────
// Device Registry — gestisce announce da Rasp/ESP32
// Flusso: announce → verifica room con YOLO → invia config retained
// ─────────────────────────────────────────────────────────────────────────────

const p = msg.payload || {};
const deviceId   = p.device_id;
const roomClaim  = p.room_claim || 'unknown';
const deviceType = p.type || 'unknown';
const ip         = p.ip || 'unknown';
const now        = Date.now();

if (!deviceId) return null;

let brain = global.get('gaiaBrain') || {};
brain.devices = brain.devices || {};

// Firma YOLO per stanza: oggetti tipici di ogni stanza
const ROOM_SIGNATURES = {
    salotto:   ['couch', 'tv', 'chair', 'potted plant', 'remote'],
    sala:      ['dining table', 'chair', 'cup', 'bowl'],
    cucina:    ['refrigerator', 'bowl', 'cup', 'bottle', 'microwave', 'oven'],
    camera:    ['bed', 'person'],
    bagno:     ['toilet', 'sink', 'toothbrush'],
    studio:    ['laptop', 'keyboard', 'monitor', 'chair', 'book'],
    ingresso:  ['person', 'chair', 'backpack', 'handbag', 'umbrella'],
    garage:    ['car', 'bicycle', 'motorcycle'],
    giardino:  ['bicycle', 'dog', 'cat', 'potted plant'],
};

// Verifica YOLO: quanti oggetti signature sono presenti nella stanza claimed?
function yoloVerify(room) {
    const roomData = (brain.rooms || {})[room];
    if (!roomData || !roomData.objects) return { score: 0, verified: false };
    const detectedObjs = Object.keys(roomData.objects).map(k => k.toLowerCase());
    const sig = ROOM_SIGNATURES[room] || [];
    if (sig.length === 0) return { score: 0.5, verified: false }; // stanza non mappata
    const matches = sig.filter(s => detectedObjs.some(d => d.includes(s)));
    const score = matches.length / sig.length;
    return { score: Math.round(score * 100), verified: score >= 0.3 };
}

// Recupera device esistente o crea nuovo
const existing = brain.devices[deviceId] || {};
const assignedRoom = existing.room || roomClaim; // room assegnata dall'admin ha priorità

const yolo = yoloVerify(assignedRoom);

brain.devices[deviceId] = {
    ...existing,
    id:           deviceId,
    type:         deviceType,
    ip:           ip,
    room:         assignedRoom,
    room_claim:   roomClaim,
    verified:     yolo.verified,
    yolo_score:   yolo.score,
    lastSeen:     now,
    online:       true,
    status:       existing.status || 'active',
};

global.set('gaiaBrain', brain);

// Config da inviare al device (retained → sopravvive ai restart del Pi)
const configPayload = {
    room:           assignedRoom,
    verified:       yolo.verified,
    yolo_score:     yolo.score,
    assigned_by:    existing.room ? 'admin' : 'claim',
    ts:             now,
};

msg.configTopic   = `gaia/devices/${deviceId}/config`;
msg.configPayload = JSON.stringify(configPayload);

node.warn(`[Registry] ${deviceId} → room=${assignedRoom} verified=${yolo.verified} score=${yolo.score}%`);

return msg;

// Imposta topic e payload per MQTT out (retained)
msg.topic   = msg.configTopic;
msg.payload = msg.configPayload;
msg.retain  = true;
return msg;

// ─────────────────────────────────────────────────────────────────────────────
// Admin: assegna stanza a device
// POST /gaia/device/assign  {device_id, room}
// ─────────────────────────────────────────────────────────────────────────────

const body = msg.payload || {};
const deviceId = body.device_id;
const newRoom  = body.room;

if (!deviceId || !newRoom) {
    msg.statusCode = 400;
    msg.payload = { ok: false, error: 'device_id e room richiesti' };
    return [null, msg];
}

let brain = global.get('gaiaBrain') || {};
brain.devices = brain.devices || {};

if (!brain.devices[deviceId]) {
    msg.statusCode = 404;
    msg.payload = { ok: false, error: `device ${deviceId} non trovato` };
    return [null, msg];
}

const old = brain.devices[deviceId].room;
brain.devices[deviceId].room     = newRoom;
brain.devices[deviceId].verified = false;   // richiede riverifica YOLO
brain.devices[deviceId].assigned_by = 'admin';

global.set('gaiaBrain', brain);

// Pubblica nuova config retained
const configPayload = JSON.stringify({
    room:        newRoom,
    verified:    false,
    assigned_by: 'admin',
    ts:          Date.now(),
});

msg.configTopic   = `gaia/devices/${deviceId}/config`;
msg.configPayload = configPayload;

node.warn(`[Registry] Admin: ${deviceId} room ${old} → ${newRoom}`);

// Auto-pulizia: se la stanza vecchia resta senza device, i suoi dati live e
// i topic retained (scene, voice status) diventano orfani — via subito.
if (old && old !== newRoom) {
    const stillThere = Object.values(brain.devices)
        .filter(d => d.room === old && d.id !== deviceId);
    if (!stillThere.length) {
        if ((brain.rooms || {})[old]) delete brain.rooms[old];
        global.set('gaiaBrain', brain);
        [`gaia/scene/${old}`, `gaia/voice/status/${old}`].forEach(t =>
            node.send([{ configTopic: t, configPayload: '' }, null]));
        node.warn(`[Registry] Stanza '${old}' orfana dopo lo spostamento → pulita`);
    }
}

const httpResp = { ...msg, payload: { ok: true, device_id: deviceId, room: newRoom } };
return [msg, httpResp];

// Imposta topic e payload per MQTT out (retained)
msg.topic   = msg.configTopic;
msg.payload = msg.configPayload;
msg.retain  = true;
return msg;

// GET /gaia/devices → lista tutti i device registrati
const brain = global.get('gaiaBrain') || {};
const devices = brain.devices || {};
const now = Date.now();
const list = Object.values(devices).map(d => ({
    ...d,
    online: d.lastSeen && (now - d.lastSeen) < 120000,   // online se visto negli ultimi 2min
}));
msg.payload = { devices: list, ts: now };
return msg;

// GET /gaia/ota/* → serve qualsiasi file sotto pi/ del repo
// Es: /gaia/ota/voice/main.py         → pi/voice/main.py
//     /gaia/ota/voice/models/gaia_verifier.pkl → pi/voice/models/gaia_verifier.pkl
//     /gaia/ota/yolo/main.py           → pi/yolo/main.py
const PI_BASE = '/home/core/core-node-0/pi';
const ALLOWED_SERVICES = ['yolo','mediapipe','voice','camera','agent'];

const relPath = msg.req.params[0] || '';
const parts   = relPath.split('/').filter(Boolean);
const service = parts[0];

if (!ALLOWED_SERVICES.includes(service)) {
    msg.statusCode = 403;
    msg.payload = 'Servizio non consentito: ' + service;
    return msg;
}

// Path traversal check (precauzione)
if (relPath.includes('..')) {
    msg.statusCode = 403;
    msg.payload = 'Path non consentito';
    return msg;
}

const fullPath = PI_BASE + '/' + relPath;
try {
    const data = fs.readFileSync(fullPath);
    const isPkl = fullPath.endsWith('.pkl');
    msg.headers = { 'Content-Type': isPkl ? 'application/octet-stream' : 'text/plain; charset=utf-8' };
    msg.payload = data;
} catch(e) {
    msg.statusCode = 404;
    msg.payload = 'File non trovato: ' + relPath + ' (' + e.message + ')';
}
return msg;

// POST /gaia/ota/push
// Body: { service: "voice"|"yolo"|"mediapipe"|"camera", script: "main.py", restart: true }
const body    = msg.payload || {};
const service = body.service || body.type;
const script  = body.script;
const restart = body.restart !== false;

const PI_BASE = '/home/core/core-node-0/pi';
const ALLOWED = ['yolo','mediapipe','voice','camera','agent'];

if (!service || !script || !ALLOWED.includes(service)) {
    msg.statusCode = 400;
    msg.payload    = { ok: false, error: 'service e script obbligatori' };
    return [null, msg];
}

const relPath  = service + '/' + script;
const fullPath = PI_BASE + '/' + relPath;
const host     = msg.req.hostname || '192.168.1.142';
const port     = 1880;

let content;
try {
    content = fs.readFileSync(fullPath);
} catch(e) {
    msg.statusCode = 404;
    msg.payload    = { ok: false, error: 'File non trovato: ' + relPath };
    return [null, msg];
}

const md5     = crypto.createHash('md5').update(content).digest('hex');
const version = new Date().toISOString().slice(0,16).replace('T','-').replace(':','');
const cmd = {
    script:  script,
    url:     `http://${host}:${port}/gaia/ota/${relPath}`,
    md5:     md5,
    version: version,
    service: 'gaia-' + service,
    restart: restart,
    type:    service,
};

msg.otaCommands = [cmd];
const httpResp = { ...msg, payload: { ok: true, pushing: [script], service, version, url: cmd.url, md5 } };
return [msg, httpResp];

// Pubblica ogni comando OTA su gaia/ota/broadcast
const cmds = msg.otaCommands || [];
cmds.forEach(cmd => {
    node.send({ topic: 'gaia/ota/broadcast', payload: JSON.stringify(cmd), retain: false });
});
return null;

// Riceve ack dai device: gaia/devices/+/ota/ack
const p = msg.payload || {};
let brain = global.get('gaiaBrain') || {};
brain.devices = brain.devices || {};
if (p.device_id && brain.devices[p.device_id]) {
    brain.devices[p.device_id].ota = {
        status:  p.status,
        version: p.version,
        ts:      p.ts || Date.now(),
        error:   p.error || null,
    };
    global.set('gaiaBrain', brain);
}
node.warn(`[OTA ack] ${p.device_id}: ${p.status} v${p.version}${p.error?' ERR:'+p.error:''}`);
return null;

const d = msg.payload;
const id = d.device_id;
if (!id) return null;

const devices = flow.get('devices') || {};
devices[id] = {
    device_id:    id,
    stanza:       d.stanza,
    ip:           d.ip,
    capabilities: d.capabilities || {},
    services:     d.services     || {},
    config:       d.config       || {},
    uptime:       d.uptime       || 0,
    last_seen:    Date.now(),
    online:       true
};
flow.set('devices', devices);

// Conta dispositivi online
const online = Object.values(devices).filter(x => x.online).length;
flow.set('devices_online', online);

node.status({ fill:'green', shape:'dot', text: online + ' device/s online' });
return null;

const devices = flow.get('devices') || {};
const now = Date.now();
const TIMEOUT = 90000;

let changed = false;
Object.keys(devices).forEach(id => {
    const was_online = devices[id].online;
    devices[id].online = (now - devices[id].last_seen) < TIMEOUT;
    if (was_online && !devices[id].online) {
        node.warn('Device offline: ' + id);
        changed = true;
    }
});

if (changed) flow.set('devices', devices);

const online = Object.values(devices).filter(x => x.online).length;
flow.set('devices_online', online);
node.status({ fill: online > 0 ? 'green' : 'red', shape: 'dot', text: online + '/' + Object.keys(devices).length + ' online' });
return null;

// Imposta msg.service prima di passare qui
// es. msg.service = 'yolo'
const svc = msg.service || 'yolo';
return { topic: 'gaia/device/' + msg.device_id + '/command',
         payload: JSON.stringify({ action: 'restart', service: svc }) };

// Esempio: configura un Pi con stanza + servizi
// Personalizza msg.stanza e msg.services prima di inviare
const stanza   = msg.stanza   || 'soggiorno';
const services = msg.services || { yolo: true, mediapipe: false, voice: true };

return { topic: 'gaia/device/' + msg.device_id + '/command',
         payload: JSON.stringify({
             action: 'set_config',
             stanza: stanza,
             services: Object.fromEntries(
                 Object.entries(services).map(([k,v]) => [k, { enabled: !!v }])
             )
         }) };

// Modifica url, md5, filename e device_id prima di inviare
return {
    topic: 'gaia/device/' + (msg.device_id || 'all') + '/command',
    payload: JSON.stringify({
        action:   'ota_update',
        service:  'yolo',
        url:      'http://192.168.1.142:8080/ota/Yolo-Scripts/main.py',
        md5:      msg.md5 || '',
        filename: 'main.py'
    })
};

const devices = flow.get('devices') || {};
const list = Object.values(devices).map(d => ({
    id:           d.device_id,
    stanza:       d.stanza,
    ip:           d.ip,
    online:       d.online,
    camera:       d.capabilities.camera,
    mic:          d.capabilities.mic,
    services:     d.services,
    last_seen_s:  Math.round((Date.now() - d.last_seen) / 1000)
}));
msg.payload = list;
return msg;

// Estrai stanza dal topic: gaia/voice/command/{stanza}
const parts = msg.topic.split('/');
const stanza = parts[3] || msg.payload.stanza || 'sconosciuta';
// Normalizza errori di trascrizione Whisper per nomi di stanze italiane
const STANZA_NORM = [
    [/\bsogg\w*\b/g,     'soggiorno'],
    [/\bsalot\w*\b/g,    'salotto'],
    [/\bingress\w*\b/g,  'ingresso'],
    [/\bcorrido\w*\b/g,  'corridoio'],
    [/\bcucin\w*\b/g,    'cucina'],
    [/\bcamer\w*\b/g,    'camera'],
    [/\bnott\w*\b/g,     'notte'],
    [/\bsal\w{0,2}\b/g,  'sala'],
];
let testoNorm = (msg.payload.text || '').toLowerCase().replace(/[.!?,;]+$/g, '').trim();
STANZA_NORM.forEach(([re, fix]) => { testoNorm = testoNorm.replace(re, fix); });
const testo = testoNorm;

msg.stanza = stanza;
msg.testo = msg.payload.text || '';
msg.ts = msg.payload.ts || Date.now();

let intent = 'sconosciuto';
let entita = {};

// Luci — accendi
if (/\b(accendi|apri|attiva)\b/.test(testo) && (/\b(luce|luci|lampada|tutto)\b/.test(testo) || /\b(soggiorno|salotto|sala|ingresso|corridoio|camera|notte|tv)\b/.test(testo))) {
    intent = 'luci_accendi';
    const m = testo.match(/\b(cucina|soggiorno|salotto|camera|bagno|ingresso|studio|sala|corridoio|notte|tv)\b/);
    if (m) entita.stanza_target = m[1];

// Luci — spegni
} else if (/\b(spegni|chiudi|disattiva)\b/.test(testo) && (/\b(luce|luci|lampada|tutto)\b/.test(testo) || /\b(soggiorno|salotto|sala|ingresso|corridoio|camera|notte|tv)\b/.test(testo))) {
    intent = 'luci_spegni';
    const m = testo.match(/\b(cucina|soggiorno|salotto|camera|bagno|ingresso|studio|sala|corridoio|notte|tv)\b/);
    if (m) entita.stanza_target = m[1];

// Temperatura
} else if (/\b(temperatura|termostato|caldo|freddo|gradi|quanti gradi)\b/.test(testo)) {
    intent = 'temperatura';

// Presenza — chi è in casa
} else if (/\b(chi|quante\s+persone|c'è\s+qualcuno|c'è\s+nessuno)\b/.test(testo) && /\b(casa|stanza|qui|dentro)\b/.test(testo)) {
    intent = 'presenza';
} else if (/\b(qualcuno\s+in\s+casa|persone\s+in\s+casa)\b/.test(testo)) {
    intent = 'presenza';

// Orario
} else if (/\b(che\s+ora|che\s+ore|orario|ora\s+è|ore\s+sono)\b/.test(testo)) {
    intent = 'orario';

// Data
} else if (/\b(che\s+giorno|che\s+data|giorno\s+è|data\s+è|giorno\s+siamo)\b/.test(testo)) {
    intent = 'data';

// Meteo
} else if (/\b(meteo|tempo|previsioni|piove|pioggia|neve|sole|nuvol)\b/.test(testo)) {
    intent = 'meteo';

// Musica
} else if (/\b(musica|metti|suona|riproduci|canzone|play|metti\s+su)\b/.test(testo)) {
    intent = 'musica';
    const m = testo.match(/(?:metti|suona|riproduci)\s+(.+)/);
    if (m) entita.brano = m[1].trim();

// Timer / Sveglia
} else if (/\b(timer|sveglia|ricordami|tra\s+\d+\s+minut|tra\s+un'?\s*or)\b/.test(testo)) {
    intent = 'timer';
    const m = testo.match(/(\d+)\s*(minut|second|or)/);
    if (m) { entita.valore = parseInt(m[1]); entita.unita = m[2]; }

// Stato sistema
} else if (/\b(stato|status|come\s+stai|tutto\s+ok|funzion|sei\s+sveglia)\b/.test(testo)) {
    intent = 'stato_sistema';
}

msg.intent = intent;
msg.entita = entita;

// Salva nel brain per il WebSocket
let _brain = global.get('gaiaBrain') || {};
_brain.voiceCommands = _brain.voiceCommands || [];
_brain.voiceCommands.push({ text: msg.testo, stanza, intent, ts: msg.ts || Date.now() });
if (_brain.voiceCommands.length > 20) _brain.voiceCommands = _brain.voiceCommands.slice(-20);
global.set('gaiaBrain', _brain);

node.log('intent=' + intent + ' stanza=' + stanza + ' testo="' + msg.testo + '"');

// Doppia conferma vocale + auto-enrollment (opt-in, default OFF, vedi
// docs/automazioni.md). Se lo speaker riconosciuto da gaia_listener.py
// (solo per comandi dal minipc — i Pi non hanno ancora speaker ID, vedi
// project-esp32-roadmap/voice_roadmap) corrisponde a una persona
// attualmente presente per riconoscimento facciale, chiede a
// gaia_listener.py di rifinire il profilo vocale con l'embedding gia'
// calcolato durante l'identificazione (nessuna nuova registrazione).
let autoEnrollMsg = null;
const rawSpeaker = msg.payload?.speaker || '';
const brain = global.get('gaiaBrain') || {};
if (brain.automations?.voiceAutoEnroll === true && rawSpeaker && rawSpeaker !== 'sconosciuto') {
    const presenceKey = Object.keys(brain.presence || {}).find(k => k.toLowerCase() === rawSpeaker.toLowerCase());
    const facePresent = presenceKey && brain.presence[presenceKey].present === true;
    if (facePresent) {
        autoEnrollMsg = { topic: 'gaia/admin/voice_autoenroll', payload: JSON.stringify({ name: rawSpeaker }) };
        node.log(`[Voce] Doppia conferma volto+voce per ${rawSpeaker} -> auto-enroll`);
    }
}
return [msg, autoEnrollMsg];

const STANZA_MAP = {
    soggiorno: 'Soggiorno', salotto: 'Soggiorno', sala: 'Sala',
    ingresso: 'luce_Ingresso', corridoio: 'Luce_Corridoio',
    tv: 'Area_TV_Zone', area_tv: 'Area_TV_Zone',
    notte: 'Zona_Notte_Zone', camera: 'Zona_Notte_Zone',
    tutte: 'Tutte_le_luci', tutto: 'Tutte_le_luci', casa: 'Tutte_le_luci'
};
const stanza_target = msg.entita.stanza_target || msg.stanza;
const prefix = STANZA_MAP[stanza_target] || 'Soggiorno';
msg.tts_text = 'Luci accese in ' + stanza_target;

const isCorridor = (prefix === 'Luce_Corridoio');
const item    = isCorridor ? 'Luce_Corridoio_Luminosita' : (prefix + '_Potenza');
const payload = isCorridor ? '80' : 'ON';

node.send([
    msg,
    {
        url:     'http://localhost:8080/rest/items/' + item,
        method:  'POST',
        payload: payload,
        headers: { 'Content-Type': 'text/plain' }
    }
]);
return null;

const STANZA_MAP = {
    soggiorno: 'Soggiorno', salotto: 'Soggiorno', sala: 'Sala',
    ingresso: 'luce_Ingresso', corridoio: 'Luce_Corridoio',
    tv: 'Area_TV_Zone', area_tv: 'Area_TV_Zone',
    notte: 'Zona_Notte_Zone', camera: 'Zona_Notte_Zone',
    tutte: 'Tutte_le_luci', tutto: 'Tutte_le_luci', casa: 'Tutte_le_luci'
};
const stanza_target = msg.entita.stanza_target || msg.stanza;
const prefix = STANZA_MAP[stanza_target] || 'Soggiorno';
msg.tts_text = 'Luci spente in ' + stanza_target;

const isCorridor = (prefix === 'Luce_Corridoio');
const item    = isCorridor ? 'Luce_Corridoio_Luminosita' : (prefix + '_Potenza');
const payload = isCorridor ? '0' : 'OFF';

node.send([
    msg,
    {
        url:     'http://localhost:8080/rest/items/' + item,
        method:  'POST',
        payload: payload,
        headers: { 'Content-Type': 'text/plain' }
    }
]);
return null;

const now = new Date();
const ore = now.getHours();
const min = now.getMinutes().toString().padStart(2,'0');
msg.tts_text = 'Sono le ' + ore + ' e ' + min;
return msg;

const giorni = ['domenica','lunedì','martedì','mercoledì','giovedì','venerdì','sabato'];
const mesi = ['gennaio','febbraio','marzo','aprile','maggio','giugno','luglio','agosto','settembre','ottobre','novembre','dicembre'];
const now = new Date();
msg.tts_text = 'Oggi è ' + giorni[now.getDay()] + ' ' + now.getDate() + ' ' + mesi[now.getMonth()] + ' ' + now.getFullYear();
return msg;

// Legge i dati di presenza salvati dal flow YOLO
const presenza = flow.get('persone_in_casa') || {};
const totale = presenza.totale || 0;
const stanze = presenza.stanze || {};

if (totale === 0) {
    msg.tts_text = 'Non ci sono persone rilevate in casa.';
} else if (totale === 1) {
    msg.tts_text = "C'è una persona in casa.";
} else {
    msg.tts_text = 'Ci sono ' + totale + ' persone in casa.';
}
return msg;

const temp = flow.get('temperatura_casa');
if (temp !== null && temp !== undefined) {
    msg.tts_text = 'La temperatura in casa è di ' + Math.round(temp) + ' gradi.';
} else {
    msg.tts_text = 'Non ho dati di temperatura al momento.';
}
return msg;

const brano = msg.entita.brano || '';
msg.tts_text = brano ? 'Metto ' + brano : 'Avvio la musica.';

node.send([
    msg,
    {
        topic: 'gaia/home/music/play',
        payload: JSON.stringify({ brano: brano, stanza: msg.stanza })
    }
]);
return null;

const { valore, unita } = msg.entita;
if (!valore) {
    msg.tts_text = 'Non ho capito la durata del timer.';
    return msg;
}
const unitaLabel = unita && unita.startsWith('second') ? 'secondi' :
                   unita && unita.startsWith('or')     ? (valore === 1 ? 'ora' : 'ore') :
                   (valore === 1 ? 'minuto' : 'minuti');
msg.tts_text = 'Timer impostato per ' + valore + ' ' + unitaLabel + '.';

// Calcola ms
const ms = unita && unita.startsWith('second') ? valore * 1000 :
           unita && unita.startsWith('or')     ? valore * 3600000 :
           valore * 60000;

const stanza = msg.stanza;
setTimeout(() => {
    node.send([null, {
        topic: 'gaia/voice/tts/' + stanza,
        payload: JSON.stringify({ text: 'Timer scaduto!', stanza: stanza, ts: Date.now() })
    }]);
}, ms);

return [msg, null];

const risposte = [
    'Non ho capito. Puoi ripetere?',
    'Scusa, non ho compreso. Riprova.',
    'Non sono sicura di aver capito. Puoi riformulare?'
];
msg.tts_text = risposte[Math.floor(Math.random() * risposte.length)];
return msg;

msg.topic   = 'gaia/voice/tts/' + msg.stanza;
msg.payload = JSON.stringify({
    text:   msg.tts_text,
    stanza: msg.stanza,
    intent: msg.intent,
    ts:     Date.now()
});
return msg;

const parts = msg.topic.split('/');
const stanza = parts[3];
const stati = flow.get('voice_status') || {};
// Payload vuoto = retained cancellato (voice spento/stanza pulita) → via
// l'entry invece di sporcare i log con errori di parse.
let p = msg.payload;
if (Buffer.isBuffer(p)) p = p.toString('utf8');
if (typeof p === 'string') {
    if (!p.trim()) { delete stati[stanza]; flow.set('voice_status', stati); return null; }
    try { p = JSON.parse(p); } catch (e) { return null; }
}
if (!p || typeof p !== 'object') return null;
stati[stanza] = {
    state:  p.state,
    ts:     p.ts,
    aggiornato: Date.now()
};
flow.set('voice_status', stati);
