        node.send({ topic: 'telegram/alert', payload: `🌱 ${id} ha bisogno d'acqua (umidita ${moisture}%)` });
    }
});
return null;

const brain = global.get('gaiaBrain') || {};
if (brain.automations?.awayMode !== true) return null;
const now = Date.now();
const AWAY_THRESHOLD_MS = 30 * 60 * 1000; // 30 minuti senza nessuno in casa
const anyoneHome = Object.values(brain.presence || {}).some(p => p.present);
if (anyoneHome) {
    global.set('awayModeTriggeredAt', null);
    return null;
}
const lastSeenTimes = Object.values(brain.presence || {}).map(p => p.lastSeen || 0);
const mostRecentLastSeen = lastSeenTimes.length ? Math.max(...lastSeenTimes) : 0;
if (mostRecentLastSeen === 0 || (now - mostRecentLastSeen) < AWAY_THRESHOLD_MS) return null;
if (global.get('awayModeTriggeredAt')) return null; // gia' fatto per questa assenza
global.set('awayModeTriggeredAt', now);
node.send([null, {
    url: 'http://localhost:8080/rest/items/Tutte_le_luci_Potenza', method: 'POST',
    headers: { 'Content-Type': 'text/plain' }, payload: 'OFF'
}]);
node.send({ topic: 'telegram/alert',
    payload: `🏠 Nessuno in casa da oltre ${Math.round(AWAY_THRESHOLD_MS / 60000)} minuti — luci spente automaticamente` });
return null;

const brain = global.get('gaiaBrain') || {};
if (brain.automations?.welcomeScene !== true) return null;
const now = Date.now();
const hour = new Date().getHours();
const isNight = hour < 6 || hour >= 20;
if (!isNight) return null;
const lastWelcome = global.get('lastWelcomeScene') || {};
const COOLDOWN = 2 * 3600 * 1000; // non ripetere per la stessa persona entro 2 ore
Object.entries(brain.presence || {}).forEach(([name, p]) => {
    if (!p.present || name.startsWith('unknown')) return;
    const enterTs = p.enterTs || 0;
    const justArrived = enterTs > 0 && (now - enterTs) < 5 * 60 * 1000; // finestra = ciclo timer
    if (justArrived && (now - (lastWelcome[name] || 0)) > COOLDOWN) {
        lastWelcome[name] = now;
        global.set('lastWelcomeScene', lastWelcome);
        node.send([null, {
            url: 'http://localhost:8080/rest/items/luce_Ingresso_Potenza', method: 'POST',
            headers: { 'Content-Type': 'text/plain' }, payload: 'ON'
        }]);
        node.send([null, {
            url: 'http://localhost:8080/rest/items/luce_Ingresso_Luminosita', method: 'POST',
            headers: { 'Content-Type': 'text/plain' }, payload: '60'
        }]);
        node.send({ topic: 'telegram/alert', payload: `👋 Bentornato ${name}! Luce ingresso accesa.` });
    }
});
return null;

const brain = global.get('gaiaBrain') || {};
if (brain.automations?.touchdesignerLighting !== true) return null;
// Topic atteso: gaia/touchdesigner/lighting/<ItemOpenHAB>/<campo>
// campo in {Potenza, Luminosita, Colore, Color_Temperature} -- item reale, vedi
// memory project-openhab-hue-items per i nomi. Nessuna mappa stanza->item qui:
// chi configura TouchDesigner deve puntare direttamente all'item OpenHAB reale.
const parts = msg.topic.split('/');
if (parts.length !== 5 || parts[2] !== 'lighting') return null;
const item = parts[3];
const field = parts[4];
const ALLOWED_FIELDS = ['Potenza', 'Luminosita', 'Colore', 'Color_Temperature'];
if (!ALLOWED_FIELDS.includes(field)) return null;

// throttle: max 1 comando per item+campo ogni 200ms, TouchDesigner puo' mandare
// molto piu' spesso di quanto OpenHAB debba/possa incassare
const now = Date.now();
const lastSent = global.get('tdLightingLastSent') || {};
const key = `${item}_${field}`;
if (now - (lastSent[key] || 0) < 200) return null;
lastSent[key] = now;
global.set('tdLightingLastSent', lastSent);

let payload = msg.payload;
if (typeof payload === 'object') payload = JSON.stringify(payload);
return {
    url: `http://localhost:8080/rest/items/${item}_${field}`, method: 'POST',
    headers: { 'Content-Type': 'text/plain' }, payload: String(payload)
};

// GET /gaia/room-guess?room=<chiave_stanza_attuale>
// Non assegna nulla — suggerisce solo la stanza piu' probabile in base agli
// oggetti YOLO visti da quella telecamera, stesse firme del Device Registry
// (yoloVerify) ma usate per indovinare invece che per verificare una claim.
const brain = global.get('gaiaBrain') || {};
const room = (msg.req.query.room || '').trim();

const ROOM_SIGNATURES = {
    salotto:   ['couch', 'tv', 'chair', 'potted plant', 'remote'],
    sala:      ['dining table', 'chair', 'cup', 'bowl'],
    cucina:    ['refrigerator', 'bowl', 'cup', 'bottle', 'microwave', 'oven'],
    camera:    ['bed', 'person'],
    bagno:     ['toilet', 'sink', 'toothbrush'],
    studio:    ['laptop', 'keyboard', 'monitor', 'chair', 'book'],
    ingresso:  ['person', 'chair', 'backpack', 'handbag', 'umbrella'],
    garage:    ['car', 'bicycle', 'motorcycle'],
    giardino:  ['bicycle', 'dog', 'cat', 'potted plant'],
};

if (!room) {
    msg.statusCode = 400;
    msg.payload = { ok: false, error: 'query param "room" obbligatorio (chiave stanza attuale in brain.rooms)' };
    return msg;
}

const roomData = (brain.rooms || {})[room];
const objects = roomData?.objects || {};
const detectedObjs = Object.keys(objects).map(k => k.toLowerCase());

if (detectedObjs.length === 0) {
    msg.statusCode = 200;
    msg.payload = { ok: true, room, candidates: [], best: null,
                    message: 'Nessun oggetto rilevato ancora da questa telecamera' };
    return msg;
}

const candidates = Object.entries(ROOM_SIGNATURES).map(([candidateRoom, sig]) => {
    const matches = sig.filter(s => detectedObjs.some(d => d.includes(s)));
    const score = Math.round((matches.length / sig.length) * 100);
    return { room: candidateRoom, score, matched_objects: matches };
}).sort((a, b) => b.score - a.score);

msg.statusCode = 200;
msg.payload = {
    ok: true,
    room,
    detected_objects: detectedObjs,
    candidates,
    best: candidates[0]?.score > 0 ? candidates[0] : null,
};
return msg;

// Le risposte ai comandi vocali dati al minipc arrivano qui come JSON
// {text, stanza, intent, ts} (da "Build TTS payload"/"Timer", tab GAIA Voice) --
// diverso da casa/tts/play (pensieri spontanei, gia' testo semplice) che alimenta
// la stessa "Clean Text" piu' sotto. Prima di questo fix nessuno ascoltava
// gaia/voice/tts/minipc: le risposte finivano su MQTT e non venivano mai lette
// ad alta voce sul miniPC (il Pi invece le legge, si iscrive al suo topic
// gaia/voice/tts/{stanza} in pi/voice/main.py).
let text = '';
try {
    const p = typeof msg.payload === 'string' ? JSON.parse(msg.payload) : msg.payload;
    text = (p && p.text || '').toString().trim();
} catch (e) {
    text = (msg.payload || '').toString().trim();
}
if (!text) return null;
// Vocabolario Asemico: espone l'ultimo TTS al payload WS (ThreeViewEngineGAME
// legge gaiaLastTts) cosi' la welcome puo' "scrivere" cio' che Gaia dice.
global.set('gaiaLastTts', { text: text, ts: Date.now() });
msg.payload = text;
return msg;

// Profilo semantico dei device (docs/gaia-semantico.md, contratto 1).
// Retained per-device: capability hardware + servizi con endpoint.
let p = msg.payload;
if (typeof p === 'string') { try { p = JSON.parse(p); } catch (e) { return null; } }
if (!p || !p.device_id) return null;

let brain = global.get('gaiaBrain') || {};
brain.devices = brain.devices || {};
const d = brain.devices[p.device_id] || { id: p.device_id };
d.profile  = p;
d.role     = p.role || d.role;
d.ip       = p.ip || d.ip;
d.lastSeen = Date.now();
d.online   = true;

// F4: capability → moduli suggeriti (l'hardware decide cosa si PUÒ attivare;
// l'attivazione resta opt-in dell'utente da Pi Manager)
const CAP_MODULES = {
    camera:    ['camera', 'yolo', 'mediapipe'],
    mic:       ['voice'],
    audio_out: ['tts', 'mediaplayer'],
    display:   ['kiosk-welcome'],
    midi:      ['av-herbarium'],
    i2c:       ['av-herbarium'],
};
const caps = p.capabilities || {};
const sugg = new Set();
for (const [cap, mods] of Object.entries(CAP_MODULES)) {
    const v = caps[cap];
    if (v && (!Array.isArray(v) || v.length)) mods.forEach(m => sugg.add(m));
}
d.suggested_modules = [...sugg];
brain.devices[p.device_id] = d;
global.set('gaiaBrain', brain);
return null;

// Tutti i profili device noti — consumato da cameras.html e dal
// scene worker per scoprire gli endpoint (mjpeg, tts, ...) senza hardcode.
const brain = global.get('gaiaBrain') || {};
const out = {};
for (const [id, d] of Object.entries(brain.devices || {})) {
    if (d.profile) out[id] = { ...d.profile, room_assigned: d.room || d.profile.room, suggested_modules: d.suggested_modules || [] };
}
msg.payload = out;
msg.headers = { 'Access-Control-Allow-Origin': '*' };
return msg;

// Chi sta parlando in una stanza (F3 gaia-semantico).
// Due vie: (a) il voice della stanza registra un comando (alta confidenza);
// (b) parlato normale = volume mic alto + BOCCA APERTA da mediapipe (la
// conferma visiva evita che il rumore ambientale accenda il badge).
let p = msg.payload;
if (typeof p === 'string') { try { p = JSON.parse(p); } catch (e) { return null; } }
const stanza = (msg.topic || '').split('/').pop();
if (!stanza || !p) return null;

let brain = global.get('gaiaBrain') || {};
brain.rooms = brain.rooms || {};
const room = brain.rooms[stanza];
if (!room) return null;

const named = (room.people || []).filter(n => !String(n).startsWith('unknown'));
if (!named.length) return null;
const mpPeople = (room.mediapipe && room.mediapipe.people) || [];
const mouthOpen = mpPeople.some(x => x.mouth_open);

let who = null, conf = 0;
const isStats = msg.topic.includes('/stats/');
if (isStats) {
    // (b) parlato normale: volume sopra soglia E bocca aperta
    const vol = p.vol || 0;
    const thr = p.silence_threshold || p.threshold || 400;
    if (vol > thr && mouthOpen) {
        who = named[0];
        conf = named.length === 1 ? 0.7 : 0.4;
    }
} else {
    // (a) comando vocale in corso
    const state = p.state || p.status;
    if (state === 'recording' || state === 'processing') {
        if (named.length === 1) { who = named[0]; conf = 0.9; }
        else if (mouthOpen)     { who = named[0]; conf = 0.5; }
    }
}

if (who) {
    room.speaking = { name: who, ts: Date.now(), confidence: conf };
    global.set('gaiaBrain', brain);
}
return null;

// Descrizioni scena dal worker VLM (F5): com'è fatta ogni stanza.
let p = msg.payload;
if (typeof p === 'string') { try { p = JSON.parse(p); } catch (e) { return null; } }
if (!p || !p.room || !p.description) return null;
let brain = global.get('gaiaBrain') || {};
brain.rooms = brain.rooms || {};
brain.rooms[p.room] = brain.rooms[p.room] || { id: p.room, name: p.room, people: [] };
const prevScene = (brain.rooms[p.room].scene || {}).text;
brain.rooms[p.room].scene = { text: p.description, model: p.model, ts: p.ts || Date.now() };
// una stanza che CAMBIA aspetto incuriosisce (sorgente mood curiosity)
if (prevScene && prevScene !== p.description && brain.mood) {
    brain.mood.curiosity = Math.min(1, (brain.mood.curiosity || 0) + 0.1);
}
global.set('gaiaBrain', brain);
return null;

// GET /gaia/rooms → stato stanze note al brain + device assegnati.
// Serve all'admin per vedere/pulire stanze orfane (device spostati).
const brain = global.get('gaiaBrain') || {};
const devices = Object.values(brain.devices || {});
const graphRooms = Object.keys(brain.roomGraph || {}).filter(k => k !== '_v');
const out = {};
const devIn = name => devices.filter(d => d.room === name).map(d => d.id);
for (const [name, r] of Object.entries(brain.rooms || {})) {
    out[name] = {
        in_map:      graphRooms.includes(name),
        devices:     devIn(name),
        people:      r.people || [],
        speaking:    r.speaking || null,
        has_scene:   !!r.scene,
        last_update: r.lastUpdate || r.ts || null,
    };
}
for (const name of graphRooms) {
    if (!out[name]) out[name] = { in_map: true, devices: devIn(name), people: [],
                                  speaking: null, has_scene: false, last_update: null };
}
msg.payload = { rooms: out, ts: Date.now() };
msg.headers = { 'Access-Control-Allow-Origin': '*' };
return msg;

// POST /gaia/rooms/clean {room, force?}
// Rimuove una stanza sbagliata/orfana: dati live nel brain, archi nei grafi
// APPRESI, topic retained (scene, voice status). La mappa disegnata
// (roomGraph) non si tocca da qui: quella è la casa, non i dati.
const body = msg.payload || {};
const room = (body.room || '').trim().toLowerCase();
if (!room) { msg.statusCode = 400; msg.payload = { ok: false, error: 'room richiesta' }; return [null, msg]; }

let brain = global.get('gaiaBrain') || {};
const assigned = Object.values(brain.devices || {}).filter(d => d.room === room).map(d => d.id);
if (assigned.length && body.force !== true) {
    msg.statusCode = 409;
    msg.payload = { ok: false, error: `stanza in uso da: ${assigned.join(', ')} — riassegna prima il device o passa force:true` };
    return [null, msg];
}

const cleaned = [];
if ((brain.rooms || {})[room]) { delete brain.rooms[room]; cleaned.push('brain.rooms'); }
for (const gName of ['roomGraphLearned', 'roomGraphMotion']) {
    const g = brain[gName] || {};
    let touched = false;
    if (g[room]) { delete g[room]; touched = true; }
    for (const k of Object.keys(g)) {
        if (g[k] && g[k][room] !== undefined) { delete g[k][room]; touched = true; }
    }
    if (touched) cleaned.push(gName);
}
global.set('gaiaBrain', brain);

// clear dei retained della stanza: payload vuoto + retain = il broker li scorda
const topics = [`gaia/scene/${room}`, `gaia/voice/status/${room}`];
topics.forEach(t => node.send([{ topic: t, payload: '', retain: true }, null]));

node.warn(`[Rooms] Pulita '${room}': ${cleaned.join(', ') || 'niente nel brain'} + clear ${topics.length} retained`);
msg.payload = { ok: true, room, cleaned, retained_cleared: topics };
return [null, msg];

// Health check (ogni 60s): device muti e backup vecchio → Telegram.
// Un alert per episodio + messaggio di rientro (niente spam).
const brain = global.get('gaiaBrain') || {};
const h = brain._health = brain._health || { offline: {}, backupAlerted: false };
const now = Date.now();
const out = [];

// 1. Device: heartbeat+profilo ogni 30s → muto se lastSeen > 3 min
for (const [id, d] of Object.entries(brain.devices || {})) {
    if (!d.lastSeen) continue;
    if (id.endsWith('-mp')) continue;   // publisher secondario, non un device
    const offline = now - d.lastSeen > 180000;
    const was = !!h.offline[id];
    if (offline && !was) {
        h.offline[id] = now;
        out.push(`⚠️ ${id} (${d.room || '?'}) non risponde da 3 minuti.`);
    } else if (!offline && was) {
        const mins = Math.round((now - h.offline[id]) / 60000);
        delete h.offline[id];
        out.push(`✅ ${id} (${d.room || '?'}) è tornato online (giù ~${mins} min).`);
    }
}

// 2. Dead-man backup: gaia/backup/status (retained) salvato in brain._backup
const b = brain._backup;
if (b && b.ts) {
    const stale = now - b.ts > 26 * 3600 * 1000;
    const failed = b.ok === false;
    if ((stale || failed) && !h.backupAlerted) {
        h.backupAlerted = true;
        out.push(failed
            ? "⚠️ Backup GAIA: l'ultimo backup è FALLITO — vedi /media/core/D/backups/gaia_backup.log"
            : '⚠️ Backup GAIA: nessun backup completato nelle ultime 26 ore.');
    } else if (!stale && !failed) {
        h.backupAlerted = false;
    }
}

global.set('gaiaBrain', brain);
if (!out.length) return null;
return [out.map(content => ({ payload: {
    chatId: 1180846253, type: 'message', content } }))];

// gaia/backup/status (retained) → brain._backup per il dead-man switch
let p = msg.payload;
if (typeof p === 'string') { try { p = JSON.parse(p); } catch (e) { return null; } }
if (!p || !p.ts) return null;
let brain = global.get('gaiaBrain') || {};
brain._backup = { ok: p.ok !== false, ts: p.ts, size_bytes: p.size_bytes || 0 };
global.set('gaiaBrain', brain);
return null;

// POST /gaia/device/forget {device_id, force?}
// Dimentica un device morto/relitto: entry nel registry + clear dei suoi
// retained (config, profile, status agent). Rifiuta se vivo (<10 min).
const body = msg.payload || {};
const id = (body.device_id || '').trim();
if (!id) { msg.statusCode = 400; msg.payload = { ok: false, error: 'device_id richiesto' }; return [null, msg]; }

let brain = global.get('gaiaBrain') || {};
const d = (brain.devices || {})[id];
if (!d) { msg.statusCode = 404; msg.payload = { ok: false, error: `${id} non in registry` }; return [null, msg]; }
const ageMin = d.lastSeen ? Math.round((Date.now() - d.lastSeen) / 60000) : null;
if (ageMin !== null && ageMin < 10 && body.force !== true) {
    msg.statusCode = 409;
    msg.payload = { ok: false, error: `${id} visto ${ageMin} min fa — sembra vivo. Usa force:true per insistere` };
    return [null, msg];
}
delete brain.devices[id];
global.set('gaiaBrain', brain);

const topics = [`gaia/devices/${id}/config`, `gaia/devices/${id}/profile`, `gaia/device/${id}/status`];
topics.forEach(t => node.send([{ topic: t, payload: '', retain: true }, null]));
node.warn(`[Registry] Dimenticato device ${id} (muto da ${ageMin} min)`);
msg.payload = { ok: true, device_id: id, was_silent_min: ageMin, retained_cleared: topics };
return [null, msg];

// Preset radio condivisi (web + Telegram). Per modificarli si edita QUI.
const PRESETS = [
    { id: 'rai1',       name: 'Rai Radio 1',       url: 'https://icestreaming.rai.it/1.mp3' },
    { id: 'rai2',       name: 'Rai Radio 2',       url: 'https://icestreaming.rai.it/2.mp3' },
    { id: 'rai3',       name: 'Rai Radio 3',       url: 'https://icestreaming.rai.it/3.mp3' },
    { id: 'virgin',     name: 'Virgin Radio',      url: 'https://icy.unitedradio.it/Virgin.mp3' },
    { id: '105',        name: 'Radio 105',         url: 'https://icy.unitedradio.it/Radio105.mp3' },
    { id: 'montecarlo', name: 'Radio Monte Carlo', url: 'https://icy.unitedradio.it/RMC.mp3' },
    { id: 'popolare',   name: 'Radio Popolare',    url: 'https://live.radiopopolare.it/mp3' },
    { id: 'paradise',   name: 'Radio Paradise',    url: 'https://stream.radioparadise.com/mp3-192' },
];
global.set('gaiaMediaPresets', PRESETS);
node.warn(`[Media] ${PRESETS.length} preset radio caricati`);
return null;

// gaia/media/{room}/status → brain.media[room] (payload vuoto = player via)
const room = msg.topic.split('/')[2];
let brain = global.get('gaiaBrain') || {};
brain.media = brain.media || {};
let p = msg.payload;
if (Buffer.isBuffer(p)) p = p.toString('utf8');
if (typeof p === 'string') {
    if (!p.trim()) { delete brain.media[room]; global.set('gaiaBrain', brain); return null; }
    try { p = JSON.parse(p); } catch (e) { return null; }
}
if (!p || typeof p !== 'object') return null;
brain.media[room] = { state: p.state, title: p.title, url: p.url,
                      volume: p.volume, ts: p.ts || Date.now() };
global.set('gaiaBrain', brain);
return null;

// GET /gaia/media/state → player per stanza + preset (per la card web)
const brain = global.get('gaiaBrain') || {};
const players = {};
for (const d of Object.values(brain.devices || {})) {
    const mp = d.profile && (d.profile.services || {}).mediaplayer;
    if (mp) players[d.room || d.id] = { device: d.id, service: mp.state,
                                        ...(brain.media || {})[d.room] };
}
msg.payload = { players, presets: global.get('gaiaMediaPresets') || [], ts: Date.now() };
msg.headers = { 'Access-Control-Allow-Origin': '*' };
return msg;

// POST /gaia/media/cmd {room, action, url?, value?} → publish al player
const b = msg.payload || {};
if (!b.room || !b.action) {
    msg.statusCode = 400; msg.payload = { ok: false, error: 'room e action richiesti' };
    return [null, msg];
}
const out = { topic: `gaia/media/${b.room}/command`,
              payload: JSON.stringify({ action: b.action, url: b.url, value: b.value }) };
const resp = { ...msg, payload: { ok: true, room: b.room, action: b.action },
               headers: { 'Access-Control-Allow-Origin': '*' } };
return [out, resp];

// gaia/notify/telegram {chatId?, text} → messaggio Telegram
// Canale riusabile: anche i servizi python (gaia_admin) possono notificare.
let p = msg.payload;
if (typeof p === 'string') { try { p = JSON.parse(p); } catch (e) { return null; } }
if (!p || !p.text) return null;
msg.payload = { chatId: p.chatId || 1180846253, type: 'message', content: p.text };
return msg;

// Note dalle piante (gaia/herbarium/{stanza}/note) → evento normalizzato
let p = msg.payload;
if (typeof p === 'string') { try { p = JSON.parse(p); } catch (e) { return null; } }
if (!p || p.note === undefined) return null;
const room = msg.topic.split('/')[2];
msg.event = {
    ts: Date.now(), topic: msg.topic,
    source: 'herbarium', category: 'music',
    value: p.note, velocity: p.velocity || 0,
    person: null, room: room, device: room, confidence: null,
};
// buffer rolling per le superfici web (welcome via WS) — vedi ThreeViewEngineGAME
const buf = global.get('gaiaHerbNotes') || [];
buf.push({ note: p.note, velocity: p.velocity || 0, room: room, ts: msg.event.ts });
global.set('gaiaHerbNotes', buf.slice(-60));
return msg;

// flag persistito come retained MQTT (il context Node-RED è in-memory)
let p = msg.payload;
if (typeof p === 'string') { try { p = JSON.parse(p); } catch (e) { return null; } }
if (!p || typeof p !== 'object') return null;
global.set('gaiaHerbWeb', p.enabled !== false);
return null;

let p = msg.payload;
if (typeof p === 'string') { try { p = JSON.parse(p); } catch (e) { p = {}; } }
const enabled = !!(p && p.enabled);
global.set('gaiaHerbWeb', enabled);
// retained: sopravvive ai riavvii di Node-RED (riletto da Herbweb Config)
const toMqtt = { topic: 'gaia/config/herbweb', payload: JSON.stringify({ enabled }), retain: true, qos: 1 };
msg.payload = { ok: true, enabled };
return [[toMqtt], [msg]];

// Level-up → scena luci celebrativa nel colore dell'archetipo, poi ripristino.
// Lo stato precedente si legge VIVO da OpenHAB (brain.lights può essere stantio).
let p = msg.payload;
if (typeof p === 'string') { try { p = JSON.parse(p); } catch (e) { return null; } }
if (!p || !p.level) return null;

const now = Date.now();
if (now - (context.get('lastFx') || 0) < 30000) return null;   // anti-doppione
context.set('lastFx', now);

const CLASS_HSB = { Mago: '190,90,70', Bardo: '300,80,70', Guerriero: '0,100,70',
                    Druido: '115,80,65', Neutro: '45,15,80' };
const colore = CLASS_HSB[p.class] || CLASS_HSB.Neutro;

const OH = 'http://localhost:8080/rest/items';
async function st(item) {
    try { const r = await fetch(`${OH}/${item}/state`); return (await r.text()).trim(); }
    catch (e) { return null; }
}
const prevPower = (await st('Tutte_le_luci_Potenza')) === 'ON';
const prevBri   = parseInt(await st('Tutte_le_luci_Luminosita'), 10) || 50;
const prevColor = await st('Tutte_le_luci_Colore');

node.send({ gaiaAction: { stanza: 'tutte', colore: colore, brightness: 70 } });
node.status({ fill: 'yellow', shape: 'dot', text: `livello ${p.level} — ${p.class}` });

setTimeout(() => {
    if (!prevPower) {
        node.send({ gaiaAction: { stanza: 'tutte', power: false } });
    } else {
        node.send({ gaiaAction: { stanza: 'tutte', brightness: prevBri } });
        if (prevColor && /^\d+,\d+,\d+$/.test(prevColor) && prevColor !== '0,0,0')
            node.send({ gaiaAction: { stanza: 'tutte', colore: prevColor } });
    }
    node.status({});
}, 10000);
return null;

// Tap Switch → riti. 1: luce dell'archetipo · 2: musica sì/no (soggiorno)
// 3: vessillo su Telegram · 4: quiete (stop musica ovunque).
let p = msg.payload;
if (typeof p === 'string') { try { p = JSON.parse(p); } catch (e) { return null; } }
if (!p || !p.button) return null;

const now = Date.now();
if (now - (context.get('lastRitual') || 0) < 3000) return null;   // anti-rimbalzo
context.set('lastRitual', now);

const brain = global.get('gaiaBrain') || {};
const MUSIC_ROOM = 'soggiorno';        // dove vive il Tap (adattare se si sposta)

if (p.button === 1) {
    // Rito della luce: scena archetipo 10s con ripristino live (come LevelupFX)
    const CLASS_HSB = { Mago: '190,90,70', Bardo: '300,80,70', Guerriero: '0,100,70',
                        Druido: '115,80,65', Neutro: '45,15,80' };
    const OH = 'http://localhost:8080/rest/items';
    const st = async i => { try { const r = await fetch(`${OH}/${i}/state`); return (await r.text()).trim(); } catch (e) { return null; } };
    const prevPower = (await st('Tutte_le_luci_Potenza')) === 'ON';
    const prevBri   = parseInt(await st('Tutte_le_luci_Luminosita'), 10) || 50;
    node.send([{ gaiaAction: { stanza: 'tutte', colore: CLASS_HSB[p.class] || CLASS_HSB.Neutro, brightness: 70 } }, null, null]);
    setTimeout(() => {
        node.send([{ gaiaAction: { stanza: 'tutte', power: false } }, null, null]);
        if (prevPower) node.send([{ gaiaAction: { stanza: 'tutte', brightness: prevBri } }, null, null]);
    }, 10000);
    node.status({ fill: 'yellow', shape: 'dot', text: 'rito della luce' });
}

if (p.button === 2) {
    // Musica sì/no nella stanza del Tap: toggle sul primo preset
    const playing = ((brain.media || {})[MUSIC_ROOM] || {}).state === 'playing';
    if (playing) {
        node.send([null, { topic: `gaia/media/${MUSIC_ROOM}/command`, payload: JSON.stringify({ action: 'stop' }) }, null]);
        node.status({ fill: 'grey', shape: 'dot', text: 'musica: stop' });
    } else {
        const presets = global.get('gaiaMediaPresets') || {};
        const first = Object.entries(presets)[0];
        if (first) {
            node.send([null, { topic: `gaia/media/${MUSIC_ROOM}/command`, payload: JSON.stringify({ action: 'play', url: first[1].url || first[1], title: first[0] }) }, null]);
            node.status({ fill: 'green', shape: 'dot', text: `musica: ${first[0]}` });
        }
    }
}

if (p.button === 3) {
    // Vessillo: stato RPG su Telegram
    const g = brain.gamification || {};
    const mood = (brain.mood || {}).state || 'neutra';
    const txt = `📜 Vessillo di Gaia\nLv.${g.level || 1} ${g.activeClass || 'Neutro'} — XP ${g.xp || 0}/${g.xpNextLevel || 1000}\nUmore: ${mood}\nRune: ${(g.unlockedAssets || []).length}`;
    node.send([null, { topic: 'gaia/notify/telegram', payload: JSON.stringify({ text: txt }) }, null]);
    node.status({ fill: 'blue', shape: 'dot', text: 'vessillo inviato' });
}

if (p.button === 4) {
    // Quiete: la musica tace in ogni stanza
    for (const stanza of Object.keys(brain.media || {})) {
        node.send([null, { topic: `gaia/media/${stanza}/command`, payload: JSON.stringify({ action: 'stop' }) }, null]);
    }
    node.status({ fill: 'grey', shape: 'ring', text: 'quiete' });
}
return null;
